const SriLankaMap = ({ data, serviceName }) => {
  const [hoveredDistrict, setHoveredDistrict] = useState(null);
  const [tooltipPos, setTooltipPos] = useState({ x: 0, y: 0 });

  const handleMouseMove = (e) => {
    setTooltipPos({ x: e.clientX, y: e.clientY });
  };

  const getRiskClass = (districtName) => {
    if (!data || !data[districtName]) return 'none';
    const risk = data[districtName].risk || 'None';
    return risk.toLowerCase();
  };

  return (
    <div className="sri-lanka-map-container">
      <div className="map-header">
        <h3>🗺️ {serviceName} Risk Map</h3>
        <div className="map-legend">
          <div className="legend-item"><span className="dot high"></span> High</div>
          <div className="legend-item"><span className="dot medium"></span> Med</div>
          <div className="legend-item"><span className="dot low"></span> Low</div>
        </div>
      </div>

      <div className="map-svg-wrapper" onMouseMove={handleMouseMove}>
        <svg
          viewBox="0 0 400 600"
          className="sl-map-svg"
          preserveAspectRatio="xMidYMid meet"
        >
          {DISTRICT_PATHS.map((district) => (
            <path
              key={district.name}
              d={district.d}
              className={`district-path ${getRiskClass(district.name)} ${
                hoveredDistrict?.name === district.name ? 'hovered' : ''
              }`}
              onMouseEnter={() => setHoveredDistrict({
                name: district.name,
                stats: data ? data[district.name] : null
              })}
              onMouseLeave={() => setHoveredDistrict(null)}
            />
          ))}
        </svg>

        {hoveredDistrict && (
          <div 
            className="map-tooltip"
            style={ { 
              left: tooltipPos.x + 15, 
              top: tooltipPos.y - 10 
            } }
          >
            <div className="tooltip-title">{hoveredDistrict.name}</div>
            {hoveredDistrict.stats ? (
              <div className="tooltip-stats">
                <div className="stat high">High: {hoveredDistrict.stats.High || 0}</div>
                <div className="stat medium">Med: {hoveredDistrict.stats.Medium || 0}</div>
                <div className="stat low">Low: {hoveredDistrict.stats.Low || 0}</div>
                <div className="risk-badge">Risk: {hoveredDistrict.stats.risk}</div>
              </div>
            ) : (
              <div className="tooltip-no-data">No active data for this service</div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default SriLankaMap;
